import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';
import Spinner from '../components/Spinner';

export default function PatientDashboard() {
  const { user } = useAuth();
  const [records, setRecords] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      api.get('/records?limit=5'),
      api.get('/appointments?limit=5'),
    ]).then(([r, a]) => {
      setRecords(r.data.records);
      setAppointments(a.data.appointments);
    }).finally(() => setLoading(false));
  }, []);

  if (loading) return <Spinner />;

  return (
    <div>
      <h4 className="mb-4">Welcome, {user?.name}</h4>

      <div className="row g-3 mb-4">
        <div className="col-sm-6">
          <div className="card stat-card border-start border-primary border-4">
            <div className="card-body d-flex justify-content-between align-items-center">
              <div>
                <div className="text-muted small">My Records</div>
                <div className="fs-3 fw-bold">{records.length}</div>
              </div>
              <i className="bi bi-file-medical fs-2 text-primary opacity-50" />
            </div>
          </div>
        </div>
        <div className="col-sm-6">
          <div className="card stat-card border-start border-success border-4">
            <div className="card-body d-flex justify-content-between align-items-center">
              <div>
                <div className="text-muted small">Upcoming Appointments</div>
                <div className="fs-3 fw-bold">
                  {appointments.filter((a) => a.status === 'confirmed' || a.status === 'pending').length}
                </div>
              </div>
              <i className="bi bi-calendar-check fs-2 text-success opacity-50" />
            </div>
          </div>
        </div>
      </div>

      <div className="row g-3">
        <div className="col-lg-6">
          <div className="card">
            <div className="card-header d-flex justify-content-between">
              <span>Recent Medical Records</span>
              <Link to="/appointments/new" className="btn btn-sm btn-outline-primary">Book Appointment</Link>
            </div>
            <ul className="list-group list-group-flush">
              {records.length === 0 ? (
                <li className="list-group-item text-muted text-center py-3">No records yet</li>
              ) : records.map((r) => (
                <li key={r._id} className="list-group-item">
                  <div className="d-flex justify-content-between">
                    <div>
                      <strong>{r.diagnosis}</strong>
                      <div className="text-muted small">Dr. {r.doctor?.name}</div>
                    </div>
                    <div className="text-end">
                      <div className="small text-muted">{new Date(r.visitDate).toLocaleDateString()}</div>
                      <Link to={`/records/${r._id}`} className="btn btn-sm btn-link p-0">View</Link>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>

        <div className="col-lg-6">
          <div className="card">
            <div className="card-header">Appointments</div>
            <ul className="list-group list-group-flush">
              {appointments.length === 0 ? (
                <li className="list-group-item text-muted text-center py-3">No appointments</li>
              ) : appointments.map((a) => (
                <li key={a._id} className="list-group-item">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <strong>Dr. {a.doctor?.name}</strong>
                      <div className="text-muted small">{a.reason}</div>
                    </div>
                    <div className="text-end">
                      <div className="small">{new Date(a.date).toLocaleDateString()} {a.timeSlot}</div>
                      <span className={`badge badge-status-${a.status}`}>{a.status}</span>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}
